/** @format */

import React from "react";
import "./skills.css";
import MachineLearning from "./MachineLearning";
import DataAnalysis from "./DataAnalysis";
import Webdevelopment from "./Webdevelopment";
import Frontend from "./Frontend";
import Backend from "./Backend";
import { Swiper, SwiperSlide } from "swiper/react";
import "swiper/css";
import "swiper/css/pagination";
import { Pagination } from "swiper/modules"; // Import Pagination from swiper

const Skills = () => {
	return (
		<section className="skills section" id="skills">
			<h2 className="section__title">Skills</h2>
			<span className="section__subtitle">My technical level</span>

			<Swiper
				spaceBetween={50} // Adjust this value to control spacing between the boxes
				slidesPerView={3} // Set to 3 to show three boxes initially
				pagination={{ clickable: true }}
				breakpoints={{
					768: {
						slidesPerView: 2, // Show 2 on medium screens
					},
					576: {
						slidesPerView: 1, // Show 1 on small screens
					},
				}}
				modules={[Pagination]} // Ensure Pagination is loaded as a module
			>
				<SwiperSlide>
					<Webdevelopment />
				</SwiperSlide>
				<SwiperSlide>
					<DataAnalysis />
				</SwiperSlide>
				<SwiperSlide>
					<MachineLearning />
				</SwiperSlide>
				<SwiperSlide>
					<Frontend />
				</SwiperSlide>
				<SwiperSlide>
					<Backend />
				</SwiperSlide>
			</Swiper>
		</section>
	);
};

export default Skills;
